  // Observe 'dogs chase cats stop'
  // We condition on the sequence of transitions:
  // dogs -> chase, chase -> cats, cats -> stop
  observe(Categorical({ps: wordToDistribution('dogs'), vs: vocab}), 'chase');
  observe(Categorical({ps: wordToDistribution('chase'), vs: vocab}), 'cats');
  observe(Categorical({ps: wordToDistribution('cats'), vs: vocab}), 'stop');

