// POS: 'N' (nouns), 'V' (verbs), plus special 'start' and 'stop'

// Vocabulary by POS
var nounWords = ['dogs', 'cats'];
var verbWords = ['chase', 'sleep'];

// Dirichlet priors for transitions from each state
// States: start, N, V (can transition to N, V, or stop)
var posStates = ['N', 'V', 'stop'];

// Sample transition distributions using Dirichlet priors
var transFromStart = sample(Dirichlet({alpha: Vector([1, 1, 0.1])}));
var transFromN = sample(Dirichlet({alpha: Vector([1, 1, 1])}));
var transFromV = sample(Dirichlet({alpha: Vector([1, 1, 1])}));

// Word emission distributions (fixed, uniform within POS)
var emitWord = function(pos) {
  if (pos === 'N') {
    return nounWords[randomInteger(nounWords.length)];
  } else if (pos === 'V') {
    return verbWords[randomInteger(verbWords.length)];
  } else {
    return 'stop';
  }
};

// Get transition distribution for a given state
var getTransDist = function(state) {
  if (state === 'start') {
    return Categorical({vs: posStates, ps: transFromStart});
  } else if (state === 'N') {
    return Categorical({vs: posStates, ps: transFromN});
  } else if (state === 'V') {
    return Categorical({vs: posStates, ps: transFromV});
  }
};

// Generate a sentence recursively
var generateSentence = function(currentState) {
  var nextPOS = sample(getTransDist(currentState));
  if (nextPOS === 'stop') {
    return [];
  } else {
    var word = emitWord(nextPOS);
    var rest = generateSentence(nextPOS);
    return [word].concat(rest);
  }
};

